@page "/recipes"
@page "/recipes/{Category}"

<PageTitle>Recipes - @(Category ?? "All Categories")</PageTitle>

<h1>@(Category is not null ? FormatCategory(Category) : "All Recipes")</h1>

@if (Category is null)
{
    <ul>
        <li><a href="recipes/appetizers">Appetizers</a></li>
        <li><a href="recipes/main-courses">Main Courses</a></li>
        <li><a href="recipes/desserts">Desserts</a></li>
    </ul>
}
else
{
    <div class="row">
        @foreach (var recipe in GetRecipes(Category))
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Summary</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string? Category { get; set; }

    private string FormatCategory(string category) => category.Replace("-", " ") switch
    {
        "appetizers" => "🥗 Appetizers",
        "main courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        _ => category
    };

    private List<RecipeInfo> GetRecipes(string category) => category switch
    {
        "appetizers" => new()
        {
            new(1, "Bruschetta", "Classic Italian tomato and basil bruschetta on toasted bread."),
            new(2, "Stuffed Mushrooms", "Savory mushroom caps filled with herb cream cheese."),
            new(3, "Caprese Skewers", "Fresh mozzarella, tomato, and basil on skewers."),
        },
        "main-courses" => new()
        {
            new(4, "Spaghetti Carbonara", "Creamy Roman pasta with pancetta and egg."),
            new(5, "Grilled Salmon", "Herb-crusted salmon fillet with lemon butter."),
            new(6, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato sauce."),
        },
        "desserts" => new()
        {
            new(7, "Tiramisu", "Classic Italian coffee-flavored layered dessert."),
            new(8, "Chocolate Lava Cake", "Warm cake with a molten chocolate center."),
            new(9, "Crème Brûlée", "Rich custard topped with caramelized sugar."),
        },
        _ => new()
    };

    private record RecipeInfo(int Id, string Title, string Summary);
}

@page "/recipe/{Id:int}"

<PageTitle>@(GetRecipe(Id)?.Title ?? "Recipe") - RecipeHub</PageTitle>

@{ var recipe = GetRecipe(Id); }

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <StarRating RecipeId="Id" />

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>
}

